#!/usr/bin/env node

import { spawnSync } from 'node:child_process';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const args = process.argv.slice(2);
const first = args[0] ?? '';

if (first === '--help' || first === '-h' || first === 'help') {
  process.stdout.write(`Usage:
  gg <file.gg|file.gnot> [args...]   run a GG source through gnode
  gg <gnosis-args...>                forward to the gnosis CLI

Examples:
  gg example.gg
  gg lint example.gg
`);
  process.exit(0);
}

const isGgSource = /\.(?:gg|gnot)$/i.test(first);
const target = isGgSource ? resolve(here, 'gnode.js') : resolve(here, 'gnosis.js');
const forwarded = isGgSource ? ['run', ...args] : args;

if (isGgSource && !process.env.GNODE_TRUST_PREWARMED_BUNDLE) {
  process.env.GNODE_TRUST_PREWARMED_BUNDLE = '1';
}

const result = spawnSync(process.execPath, [target, ...forwarded], {
  stdio: 'inherit',
  env: process.env,
});

if (result.error) {
  throw result.error;
}

process.exit(result.status ?? 1);
